"""
MKT Christ Commentary — Psalms chapters 55–61
Run: python3 scripts/zc-christ-psalms-55-61.py

Key decisions:
- Ps 55: vv12-14 the betrayal by a close companion → Judas type (Matt 26:48-50;
  John 13:18 quotes Ps 41:9 but Ps 55 provides the relational depth);
  v22 'throw your burden onto the LORD' → 1 Pet 5:7 direct citation
- Ps 56: v4 'What can a mere human being do to me?' → Heb 13:6 direct citation;
  v8 tears in wineskin = divine preservation of suffering → Rev 21:4
- Ps 57: v1 shadow-of-wings → Matt 23:37 (Christ gathering as hen);
  v9 'praise among the nations' → one of Paul's four OT citations in Rom 15:9
- Ps 58: vv3-4 snake-venom → Paul cites v4 in Rom 3:13 (universal sin catalogue);
  v11 God-judges-earth → Acts 17:31 judgment through Christ
- Ps 59: v3 'not for any offense of mine' → Christ's innocence before Pilate;
  v8 LORD laughs at enemies → Ps 2:4 pattern; Gethsemane-night watchmen motif
- Ps 60: v4 banner (nēs) for fearers → Isa 11:12; John 3:14 Son of Man lifted up;
  v7 'Judah is my scepter' → Gen 49:10; Rev 5:5 Lion of Judah
- Ps 61: v2 'rock higher than I' → 1 Cor 10:4 (the rock was Christ);
  vv6-7 king's days extended forever → Luke 1:33; Heb 7:24-25 eternal priesthood
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "55": {
    "1": '<p>A theme: Psalm 55 is a Maskil (an instructional poem) of David, beginning with the raw plea "Give ear to my prayer, O God; do not hide yourself from my plea for mercy." The hidden God who does not answer is the deepest fear in the Psalter\'s lament tradition (cf. Ps 10:1; 22:1; 44:24). Christ himself prays this petition in Gethsemane: "Abba, Father, everything is possible for you. Take this cup from me" (Mark 14:36). The cry that God not hide himself is the prayer that the cross appears to negate ("My God, my God, why have you forsaken me?" Matt 27:46) but the resurrection finally answers.</p>',
    "2": '<p>A theme: "Pay attention to me and answer me; I am troubled in my lament and I am agitated." The agitation (<em>ʾārîd bĕśîḥî</em>, I wander/moan in my concern) of the Psalmist in crisis is the emotional register of Gethsemane: "My soul is overwhelmed with sorrow to the point of death" (Matt 26:38). Christ enters the full reality of human anguish — not performing calm — and the prayer to be heard and answered is the prayer the Father answers not by removing the cup but by raising Christ through death.</p>',
    "3": '<p>A shadow: "because of the threatening voice of the enemy, the oppressive presence of the wicked; they bring evil upon me, and in anger they press hard against me." The threatening pressure of the enemy — voices and presence pressing hard — is the Passion narrative\'s texture. John 11:53 ("they plotted to take his life"), Matthew 26:3-5 (the Sanhedrin\'s deliberate plan), and the crowd\'s escalating pressure on Pilate (John 19:12-15: "Crucify him!") are the fulfillment of the hostile pressing of Psalm 55:3.</p>',
    "4": '<p>A shadow: "My heart is writhing in anguish within me; the terrors of death have fallen on me." The terrors of death (<em>ʾêmôt māwet</em>) that descend on the Psalmist are the Passion\'s emotional reality. Acts 2:24 states that God "raised him up, loosing the pangs of death (<em>lysas tas ōdinas tou thanatou</em>) because it was impossible for death to hold him." The "pangs" / "terrors" of death fell on Christ at Gethsemane and the cross — and the resurrection is the divine loosing of those very terrors.</p>',
    "5": '<p>A shadow: "Fear and trembling have overtaken me, and shuddering has covered me over." The triple collapse of composure — fear, trembling, shuddering — is the extreme of human vulnerability before mortal threat. In Gethsemane, Luke 22:44 records: "And being in anguish, he prayed more earnestly, and his sweat was like drops of blood falling to the ground." The shuddering of Psalm 55:5 is enacted literally in the Agony in the Garden — the one who is the source of all courage entered the full experience of human terror before death.</p>',
    "6": '<p>A revelation of God: "And I said, \'If only I had wings like a dove! I would fly away and find rest.\'" The wish for escape — dove\'s wings to flee suffering — is the honest prayer that did not override duty. Christ did not escape: "Father, if you are willing, take this cup from me; yet not my will, but yours be done" (Luke 22:42). The dove-wing escape of Psalm 55:6 is the human desire that the incarnate Son also felt, and which he voluntarily set aside. The Spirit descends as a dove at his baptism (Matt 3:16) — the dove that stays, rather than flees, empowering the mission.</p>',
    "7": '<p>A theme: "Yes, I would flee far away; I would make my dwelling in the wilderness." The wilderness as refuge — distance from human violence — is the pattern Christ actually entered at the beginning of his ministry (Matt 4:1: "Jesus was led by the Spirit into the wilderness"). But where Psalm 55:7 wishes for escape to the wilderness, Christ\'s wilderness is not escape but preparation for conflict. He emerges from the wilderness to face the very opposition Psalm 55 describes — he chose engagement over escape.</p>',
    "8": '<p>A theme: "I would hurry to my refuge from the driving wind and the storm." The shelter from storm is the image of YHWH as refuge (Ps 46:1; Isa 25:4: "a shelter from the storm"). In the NT, Christ is the shelter who calms the storm itself (Mark 4:39: "Quiet! Be still!") — not merely a refuge from the storm but the one who ends the storm. The desperate flight to shelter in Psalm 55:8 becomes, in Christ, the arrival at the one who has already stilled the chaos that threatens.</p>',
    "9": '<p>A shadow: "Confuse them, O Lord, split their tongues apart; for I see violence and contention in the city." The prayer for the confusion of violent, divisive speech in the city recalls Babel (Gen 11:7-9: "Come, let us go down and confuse their language") and echoes the judgment on Babylon of Revelation 18. The "city" of Psalm 55:9 racked by violence is Jerusalem in its corrupt state — and it is in Jerusalem that Christ is rejected and killed. The judgment on the city that opposed the Messiah comes in 70 AD (Matt 24:2).</p>',
    "10": '<p>A shadow: "Day and night they patrol its walls; iniquity and trouble are entrenched within it." The city fortified by iniquity — the watchers who enforce the corrupt order — is the Jerusalem of the Passion narrative. The chief priests, scribes, and elders (Matt 26:3) who plan against Jesus within the holy city represent the iniquity "entrenched" at the center of what should be the place of righteous rule. The city that should shelter the righteous becomes the place where the Righteous One is killed.</p>',
    "11": '<p>A shadow: "Ruin is entrenched at its center; oppression and fraud never leave its public spaces." The corruption of the city\'s center — the marketplace of the heart of the covenant community — is what Christ confronts directly in the temple cleansing (John 2:13-17; Matt 21:12-13). "My house will be called a house of prayer, but you are making it a den of robbers" (Matt 21:13): the "fraud" that "never leaves its public spaces" in Psalm 55:11 is the commercial exploitation that Christ drives out of the temple courts.</p>',
    "12": '<p>A type: "For it is not an enemy who insults me — that I could endure; nor is it someone who hates me who has risen up against me — from that I could hide." The manageable grief of an enemy\'s opposition — bearable, even hideable from — establishes the contrast with what follows. This verse frames the specific quality of Judas\'s betrayal of Christ: it was not the opposition of Rome or the Sanhedrin that wounds most deeply, but the betrayal by one of the Twelve. The Psalm\'s structure of "what I could endure" vs. "what I cannot" mirrors the Gospel\'s framing of Judas as the deepest wound.</p>',
    "13": '<p>A type: "But it is you — a person like me, my peer, my companion, the one I confided in." The identity of the betrayer as intimate peer and confidant — "my peer (<em>kĕʿerĕkî</em>), my companion (<em>ʾallûpî</em>), the one I confided in (<em>mĕyuddāʿî</em>)" — is the precise profile of Judas Iscariot. John 13:18 quotes Psalm 41:9 in the betrayal context ("He who shared my bread has turned against me"), but Psalm 55:13 provides the fuller emotional portrait. Luke 6:16 simply notes "Judas Iscariot, who became a traitor" — the one who had been confided in fully.</p>',
    "14": '<p>A type: "We shared deep, sweet conversation together; together we walked in God\'s house among the festival crowd." The shared worship and intimate dialogue — the table fellowship of Psalm 55:14 — is precisely the context of the Last Supper where the betrayal is announced (John 13:21-30). The "festival crowd" in God\'s house is the Passover setting: together they reclined at table for the covenant meal, and it is Judas who leaves that meal to betray the one who had shared everything with him. The intimacy of Psalm 55:14 is the Last Supper\'s intimacy betrayed.</p>',
    "15": '<p>A shadow: "Let death ambush them; let them go down to Sheol alive; for wickedness lives in their dwellings and among them." The imprecatory prayer for the sudden death of the betrayers and violent enemies is the justice cry of the Psalmist. Acts 1:18 records the judgment on Judas: "he fell headlong, his body burst open and all his intestines spilled out." The "going down to Sheol" language of Psalm 55:15 is a type of the eschatological judgment on those who betray covenant relationship — the judgment is already enacted in miniature in Judas\'s end.</p>',
    "16": '<p>A revelation of God: "As for me, I will call upon God, and the LORD will rescue me." The personal declaration of trust contrasted with the enemies\' fate is the pivot of Psalm 55. This is the pattern of Gethsemane → Easter: Christ calls upon God in prayer ("Father, if you are willing, take this cup from me," Luke 22:42) and the LORD rescues him — not by removing the cup but by raising him from the dead. The rescue of Psalm 55:16 is the resurrection, which comes through the very crisis that produces the prayer.</p>',
    "17": '<p>A revelation of God: "Evening and morning and at noon I cry out my lament and sigh; and he hears my voice." The threefold daily prayer — evening, morning, noon — is the pattern of constant access to YHWH (cf. Daniel\'s thrice-daily prayer, Dan 6:10). The NT promise is even broader: "pray continually" (1 Thess 5:17). Christ as the great high priest "always lives to make intercession" for his people (Heb 7:25) — the continuous intercession that Psalm 55:17\'s rhythm points toward. The "he hears my voice" is the confidence that resurrection grounds.</p>',
    "18": '<p>A revelation of God: "He ransoms me safely from the battle I am in, for they are many who oppose me." The ransom from the hostile many (<em>pādāh bĕšālôm napšî miqĕrāb-lî</em>, he redeemed my life in peace from the battle against me) is the covenant vocabulary of the Exodus. Christ\'s ransom is the ultimate redemption: Mark 10:45, "the Son of Man did not come to be served, but to serve, and to give his life as a ransom for many." The "many who oppose" in Psalm 55:18 become the "many" for whom the ransom is paid in Mark 10:45.</p>',
    "19": '<p>A revelation of God: "God will hear and afflict them, the one who is enthroned from of old — because they show no sign of change and have no fear of God." The divine response to the unrepentant — hearing, afflicting — is grounded in the eternal enthronement of YHWH. "No fear of God" (<em>ʾên ḥălîpôt lāhemô wĕlōʾ yārĕʾû ʾĕlōhîm</em>) is cited by Paul in Romans 3:18 as the culminating indictment of universal human sinfulness: "There is no fear of God before their eyes." The lack of repentance and God-fear that Psalm 55:19 condemns is the condition Paul declares universal — and which Christ addresses in the atonement.</p>',
    "20": '<p>A shadow: "He raised his hand against those who were at peace with him; he broke his covenant." The covenant-breaking by the one who was at peace — lifting the hand against friends, violating the solemn bond — is the deepest form of treachery in the ancient world. The betrayal of Jesus by Judas (who had received the dipped bread, the final sign of table-fellowship, John 13:26-27) is this covenant-breaking at its most extreme. Matthew 26:50: "Friend, do what you came for" — Jesus addresses the covenant-breaker as "friend" even in the act of betrayal.</p>',
    "21": '<p>A type: "His words were smoother than butter, yet war was in his heart; his speech was softer than oil, but it was all drawn swords." The gap between smooth speech and violent intent — honeyed words concealing weaponized intent — is the profile of hypocrisy that Christ repeatedly confronts. Matthew 26:48-49: Judas had arranged a signal — "The one I kiss is the man; arrest him." "Going at once to Jesus, Judas said, \'Greetings, Rabbi!\' and kissed him." The kiss is the "smooth as butter" speech of Psalm 55:21 — and it is the signal for arrest.</p>',
    "22": '<p>A direct citation: "Throw your burden onto the LORD, and he will hold you up; he will never let the righteous be shaken." 1 Peter 5:7 quotes this verse in the context of community care under suffering: "Cast all your anxiety on him because he cares for you." The Psalm\'s command to throw (<em>šĕlēk ʿal-YHWH yĕhābĕkā</em>) the burden onto YHWH is the OT grounding for the NT\'s call to anxiety-free trust in God\'s care. Christ is the mediator through whom the casting of burdens reaches the Father — Matthew 11:28: "Come to me, all you who are weary and burdened, and I will give you rest."</p>',
    "23": '<p>A revelation of God: "But you, O God, will bring them down into the pit of ruin; men of bloodshed and treachery will not reach half their days. But I — I will trust in you." The final declaration of personal trust despite the enemies\' violence is the Psalm\'s resolution. The emphatic "But I — I (<em>waʾănî</em>)" stands against the enemies\' fate. Hebrews 2:13 applies the trust-language of the Psalms to Christ: "I will put my trust in him" (citing Isa 8:17). The one who trusts in Psalm 55:23 is the type of Christ who "entrusted himself to him who judges justly" (1 Pet 2:23) through the entire Passion.</p>',
  },
  "56": {
    "1": '<p>A theme: Psalm 56 is a Michtam of David composed during his capture by the Philistines at Gath (1 Sam 21:10-15), when he feigned madness to escape. "Be merciful to me, O God, for men are trampling on me." The mercy-cry under the trampling of enemies is the Passion\'s recurring petition. Hebrews 4:16: "Let us then approach God\'s throne of grace with confidence, so that we may receive mercy and find grace to help us in our time of need." Christ, who prays for mercy in extremity, becomes the mercy-giver through whom we approach the throne.</p>',
    "2": '<p>A shadow: "My enemies trample on me all day long, for many are arrayed against me proudly." The proud array of many enemies all day long is the sustained opposition that Christ faces throughout his ministry — not only at the cross. John 7:32 (the Pharisees send temple guards to arrest him), John 11:47 (the Sanhedrin convenes against him), John 12:10 (the chief priests plot to kill Lazarus too). The "trampling all day long" of Psalm 56:2 is the cumulative pressure of sustained institutional opposition against the Messiah.</p>',
    "3": '<p>A revelation of God: "When I am afraid, I will put my trust in you." The simplest and most fundamental response to fear — trust in YHWH — is the bedrock of the Psalm. Romans 8:15: "The Spirit you received does not make you slaves, so that you live in fear again; rather, the Spirit you received brought about your adoption to sonship. And by him we cry, \'Abba, Father.\'" The fear that would drive us away from God is replaced, through Christ\'s Spirit, with the same "trust in you" posture that Psalm 56:3 models.</p>',
    "4": '<p>A direct citation: "In God — whose word I praise — in God I trust; I will not be afraid. What can a mere human being do to me?" Hebrews 13:6 quotes this verse directly: "So we say with confidence, \'The Lord is my helper; I will not be afraid. What can mere mortals do to me?\'" The Psalm\'s original context (David surrounded by hostile Philistines) and the NT application (the Christian community under persecution) share the same theological ground: the human power to harm is relativized by the divine power to protect. Christ himself demonstrates this confidence before Pilate (John 19:10-11: "Do you refuse to speak to me? Don\'t you realize I have power either to free you or to crucify you?" Jesus answered, "You would have no power over me if it were not given to you from above").</p>',
    "5": '<p>A shadow: "All day long they distort my words; all their scheming is against me for evil." The distortion of the Psalmist\'s words — twisting speech to use it against him — is the Passion narrative\'s legal strategy. Matthew 26:60-61: false witnesses testify against Jesus, misrepresenting his words about the temple ("We heard him say, \'I will destroy this temple made with human hands and in three days will build another, not made with hands\'"). The deliberate distortion of Christ\'s words about his resurrection is the fulfillment of Psalm 56:5.</p>',
    "6": '<p>A shadow: "They gather themselves to stir up trouble, they lie in ambush, they track my steps as they wait to take my life." The organized surveillance and ambush — watching every step to find the pretext — is the Synoptic Gospels\' recurring description of the religious leaders\' strategy against Jesus. Luke 20:20: "Keeping a close watch on him, they sent spies, who pretended to be sincere. They hoped to catch Jesus in something he said, so that they might hand him over to the power and authority of the governor." The "tracking steps" of Psalm 56:6 is the Pharisees\' surveillance of Jesus.</p>',
    "7": '<p>A revelation of God: "For their crime, should they escape? In wrath cast down the peoples, O God!" The justice-prayer — that those who plot crime should not escape — is the Psalm\'s appeal to divine governance. Acts 17:31: "For he has set a day when he will judge the world with justice by the man he has appointed. He has given proof of this to everyone by raising him from the dead." The judge through whom no crime escapes is the same one who was himself the target of the criminal plot — Christ vindicated and appointed as judge of those who conspired against him.</p>',
    "8": '<p>A revelation of God: "You have recorded my restless wandering; store my tears in your wineskin — are they not written in your book?" The divine preservation of the Psalmist\'s wandering and tears — everything recorded in the divine book — is the assurance of divine attentiveness to human suffering. Revelation 21:4: "He will wipe every tear from their eyes. There will be no more death or mourning or crying or pain, for the old order of things has passed away." The tears stored in the wineskin of Psalm 56:8 are the tears that Christ, who wept at Lazarus\'s tomb (John 11:35) and over Jerusalem (Luke 19:41), will one day wipe away permanently.</p>',
    "9": '<p>A revelation of God: "On the day I call out, my enemies will turn back; this I know: God is on my side." The confident knowledge — "this I know (<em>zeh ʾēdāʿ</em>)" — that God is on the side of the one who calls is the resurrection\'s epistemological ground. Romans 8:31: "What, then, shall we say in response to these things? If God is for us, who can be against us?" The enemies who "turn back" at the Psalmist\'s cry are the powers that turn back at the resurrection: the stone rolled away, the guards fleeing (Matt 28:2-4), the grave\'s power broken.</p>',
    "10": '<p>A revelation of God: "In God — whose word I praise — in the LORD — whose word I praise." The doubled praise of the divine word (<em>bĕʾlōhîm ʾăhallēl dābār bĕYHWH ʾăhallēl dābār</em>) — first <em>ʾĕlōhîm</em>, then the covenant name YHWH — is the Psalm\'s structural affirmation of trust in the divine word. John 1:1 opens with "In the beginning was the Word (<em>Logos</em>)." The word of God that Psalm 56:10 praises finds its ultimate referent in the one who is the Word — Christ as the embodiment of every divine promise and declaration.</p>',
    "11": '<p>A revelation of God: "in God I trust; I will not be afraid. What can human beings do to me?" The refrain of vv4 and 11 brackets the Psalm\'s central crisis with the double declaration of fearlessness through divine trust. Matthew 10:28: "Do not be afraid of those who kill the body but cannot kill the soul." Christ gives to his community the same fearlessness that the Psalm models — the eschatological perspective in which human power to harm is relativized by the one whose power extends beyond death.</p>',
    "12": '<p>A theme: "I have made vows to you, O God, and I will fulfill them; I will offer you my thanksgiving." The fulfillment of vows as thanksgiving after rescue is the covenant response to divine rescue. Christ\'s Gethsemane prayer ("Not my will, but yours be done") is the vow of total obedience — and Hebrews 2:12 shows Christ fulfilling his praise-vow in the post-resurrection community: "I will declare your name to my brothers and sisters; in the assembly I will sing your praises" (citing Ps 22:22). The thanksgiving after rescue is Christ\'s own praise to the Father in the gathered community.</p>',
    "13": '<p>A direct connection: "For you have saved my life from death, and my feet from stumbling, so that I may walk before God in the light that belongs to the living." The rescue from death to walk in the light of the living is resurrection language. John 8:12: "I am the light of the world. Whoever follows me will never walk in darkness, but will have the light of life." Psalm 56:13\'s "light that belongs to the living (<em>ʾôr haḥayyîm</em>)" is the resurrection light in which Christ now walks and into which he brings his people. The one who was rescued from death is himself the light of life for those who walk in him.</p>',
  },
  "57": {
    "1": '<p>A direct connection: "Be merciful to me, O God, be merciful to me, for my soul takes refuge in you; in the shadow of your wings I will take shelter until the storms of destruction pass." The "shadow of your wings" as refuge is a Psalter image for divine protection (Pss 17:8; 36:7; 61:4; 63:7; 91:4). Jesus applies the wings-image to himself in Matthew 23:37: "Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you, how often I have longed to gather your children together, as a hen gathers her chicks under her wings, and you were not willing." Christ is the one under whose wings shelter is found — and also the one whose longing to shelter was rejected.</p>',
    "2": '<p>A revelation of God: "I cry out to God Most High, to God who carries out his purpose for me." The divine purpose-fulfillment — YHWH ʾElyôn working out his plan for the Psalmist — is the providence that governs every apparent crisis. Acts 2:23: "This man was handed over to you by God\'s deliberate plan and foreknowledge; and you, with the help of wicked men, put him to death by nailing him to the cross." The God who "carries out his purpose" for David\'s crisis is the same God whose deliberate plan governs the cross — what appears as defeat is the execution of divine purpose.</p>',
    "3": '<p>A revelation of God: "He will send from heaven and rescue me; he will rebuke the one who tramples me. God will send his steadfast love and his faithfulness." The divine sending from heaven of rescue — and of ḥesed and ʾĕmet (steadfast love and faithfulness) — is the Incarnation. John 3:17: "For God did not send his Son into the world to condemn the world, but to save the world through him." The rescue sent from heaven is the Son; the steadfast love and faithfulness that accompany it are the attributes of Christ himself — "full of grace and truth" (John 1:14, the NT equivalent of ḥesed wĕʾĕmet).</p>',
    "4": '<p>A shadow: "My soul is surrounded by lions; I must lie down among those who breathe fire — human beings whose teeth are spears and arrows and whose tongue is a sharp sword." The bestial imagery of dangerous enemies — lion-people with weapon-mouths — is the Psalm\'s vivid depiction of hostile power. 1 Peter 5:8: "Your enemy the devil prowls around like a roaring lion looking for someone to devour." The "lions" of Psalm 57:4 are the human instruments of the satanic opposition that Christ defeats (1 John 3:8: "The reason the Son of God appeared was to destroy the devil\'s work"). The tongue-as-sword imagery recurs in Revelation 1:16 (the sword from Christ\'s mouth).</p>',
    "5": '<p>A direct connection: "Be exalted above the heavens, O God; let your glory be over all the earth!" The refrain of vv5 and 11 is the doxological prayer for divine cosmic exaltation — YHWH\'s glory covering the whole earth. This is fulfilled in Christ\'s ascension and glorification: Philippians 2:9-11, "Therefore God exalted him to the highest place and gave him the name that is above every name, that at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue acknowledge that Jesus Christ is Lord, to the glory of God the Father." The exaltation above the heavens of Psalm 57:5 is Christ\'s ascension; the glory over all the earth is the universal Lordship he now holds.</p>',
    "6": '<p>A shadow: "They spread a net for my feet; my soul was beaten down; they dug a pit in my path, but they themselves have fallen into it." The reversal — the pit dug for the righteous becomes the trap of the wicked — is the Wisdom pattern of evil self-defeating. Acts 4:27-28: "Herod and Pontius Pilate met together with the Gentiles and the people of Israel in this city to conspire against your holy servant Jesus... They did what your power and will had decided beforehand should happen." The pit they dug — the cross — became the instrument of their own defeat. 1 Corinthians 2:8: "None of the rulers of this age understood it, for if they had, they would not have crucified the Lord of glory."</p>',
    "7": '<p>A revelation of God: "My heart is fixed, O God, my heart is firm; I will sing and make melody!" The fixedness of the Psalmist\'s heart — unmovable, settled in trust despite the surrounding net and pit — is the foundation of praise even before rescue. Hebrews 12:2: Christ endured the cross "for the joy set before him" — the fixed heart of Psalm 57:7 is the same joy-grounded steadiness that Christ maintains through the Passion. The "singing and making melody" from a firm heart is the resurrection praise: Hebrews 2:12 shows Christ singing in the post-resurrection assembly (citing Ps 22:22).</p>',
    "8": '<p>A theme: "Awake, my honor! Awake, harp and lyre! I will rouse the dawn!" The command to rouse the dawn — to summon morning before it comes, through anticipatory praise — is the posture of the one who trusts in resurrection before it arrives. Mark 16:2: "Very early on the first day of the week, just after sunrise, they were on their way to the tomb." The "rousing of the dawn" in Psalm 57:8 is the dawn of Easter — the first light of the resurrection morning that vindicates the trust of all who praised before the answer came.</p>',
    "9": '<p>A direct connection: "I will give you thanks, O Lord, among the peoples; I will sing your praise among the nations." Paul quotes this verse in Romans 15:9 as one of four OT texts demonstrating that Christ came to bring the Gentiles into Israel\'s praise: "Therefore I will praise you among the Gentiles; I will sing hymns to your name" — citing it alongside Psalm 18:49, Deuteronomy 32:43, and Isaiah 11:10 to show that the Gentile mission was always in the OT script. The thanksgiving "among the nations" of Psalm 57:9 is the Messianic community\'s praise that the apostolic mission enacts in every people group.</p>',
    "10": '<p>A revelation of God: "For your steadfast love reaches to the heavens, your faithfulness to the skies." The cosmic reach of divine ḥesed — touching the heavens — is John 1:14\'s content: "full of grace and truth." The steadfast love and faithfulness that reach to the heavens have descended to earth in the Incarnation: the infinite ḥesed of YHWH has become personal in Jesus Christ. Ephesians 3:18-19: "to grasp how wide and long and high and deep is the love of Christ, and to know this love that surpasses knowledge." The heavens-reaching love of Psalm 57:10 is the love that surpasses knowledge in Christ.</p>',
    "11": '<p>A direct connection: "Be exalted above the heavens, O God; let your glory be over all the earth!" The closing refrain repeats v5 — the doxological petition that bookends the Psalm. The structural repetition underscores the centrality of divine exaltation as the goal and ground of all human experience — crisis, pit, net, and rescue are all subsumed under the cosmic desire for YHWH\'s glory. Christ\'s ascension ("he was taken up before their very eyes, and a cloud hid him from their sight," Acts 1:9) and present session ("he sat down at the right hand of the throne of God," Heb 12:2) are the fulfillment: exalted above the heavens, his glory over all the earth.</p>',
  },
  "58": {
    "1": '<p>A revelation of God: "Do you indeed decree what is right, you rulers? Do you judge human beings with justice?" Psalm 58 opens with a direct challenge to unjust human governance — the rhetorical question that exposes corrupt power. This is the prophetic function of the Psalter at its most confrontational. Acts 17:31 grounds all human accountability to divine justice: "For he has set a day when he will judge the world with justice by the man he has appointed." Christ is the appointed judge before whom all human "rulers" will give account for whether they "decreed what is right." The Psalm\'s challenge to unjust rulers anticipates the final judgment through Christ.</p>',
    "2": '<p>A revelation of God: "No — in your heart you devise wrongs; your hands administer violence throughout the land." The gap between the judicial office (decreeing right) and the actual conduct (devising wrongs, administering violence) is the corruption Psalm 58 exposes. Romans 2:21-23 applies similar logic to those who teach the law while breaking it. Jesus applies it directly: Matthew 23:3, "So you must be careful to do everything they tell you. But do not do what they do, for they do not practice what they preach." The devising-of-wrongs in the heart while holding judicial power is the hypocrisy Christ confronts most consistently in the Gospels.</p>',
    "3": '<p>A revelation of God: "The wicked are alienated from the womb; from their very birth they go astray, speaking lies." The radical origin of human sin — alienation from birth, going astray from the womb — is the Psalm\'s assertion of what later theology calls original sin. Psalm 51:5 parallels this: "Surely I was sinful at birth, sinful from the time my mother conceived me." Romans 3:23: "for all have sinned and fall short of the glory of God." The universal sinfulness from birth that Psalm 58:3 asserts is the condition that makes the Incarnation necessary — the one born without alienation (Luke 1:35: "the holy one to be born will be called the Son of God") to rescue those born alienated.</p>',
    "4": '<p>A direct citation: "Their venom is like the venom of a snake; they are like the deaf cobra that blocks its ear." Paul cites the next clause ("their throat is an open grave" from Ps 5:9) and the viper-venom image (combined from Pss 58:4 and 140:3) in Romans 3:13: "their throats are open graves; with their tongues they practice deceit; the poison of vipers is on their lips." Paul uses this cluster of Psalm-texts to prove universal human sinfulness. The snake-venom of Psalm 58:4 becomes part of Paul\'s sweeping indictment of all humanity before Christ — and the antidote to viper-venom is the one "lifted up like a snake in the desert" (John 3:14), whose lifting reverses the venom\'s effect.</p>',
    "5": '<p>A revelation of God: "that will not listen to the voice of those who charm, no matter how skillfully they do it." The deaf cobra that will not hear the charmer — implacable in its hostility — is the Psalm\'s image for those who resist every appeal. Luke 16:31: "If they do not listen to Moses and the Prophets, they will not be convinced even if someone rises from the dead." The one who rises from the dead is precisely the "charmer" the implacable reject: Christ risen still does not convince those who have closed their ears. The deafness of Psalm 58:5 is the deafness of those who reject even the resurrection.</p>',
    "6": '<p>A shadow: "Smash their teeth in their mouths, O God; tear out the fangs of the young lions, O LORD!" The imprecatory prayer against the weapon-teeth of the violent is the Psalm\'s justice cry. Christ\'s enemies are described in lion-and-fang imagery throughout the Psalter (Pss 7:2; 22:13; 57:4). The divine smashing of their teeth is the eschatological defeat of all hostile power: Revelation 19:15 (the sword from Christ\'s mouth conquers the armies), and the final defeat of all enemies "under his feet" (1 Cor 15:25-26). The prayer for tooth-smashing in Psalm 58:6 is the raw form of the eschatological victory that Christ achieves.</p>',
    "7": '<p>A shadow: "Let them drain away like water flowing downhill; when they draw their bows, let their arrows fall harmless." The draining of violent power — arrows rendered harmless — is the imprecatory prayer\'s image of judgment defanging evil. Ephesians 6:16: "take up the shield of faith, with which you can extinguish all the flaming arrows of the evil one." The arrows that fall harmless in Psalm 58:7 are the arrows extinguished by the shield of faith — a defense available only through the victory Christ has already won over the powers.</p>',
    "8": '<p>A shadow: "Let them be like a snail that dissolves as it goes, like a stillborn child that never sees the light of the sun." The imagery of futility — the snail that disappears in its own trail, the stillborn that never sees the light — is the Psalm\'s most vivid picture of those who never participate in the life of the coming age. John 3:19-20: "Light has come into the world, but people loved darkness instead of light because their deeds were evil... everyone who does evil hates the light." Those who "never see the light of the sun" in Psalm 58:8 are those who reject the Light of the world (John 8:12) — self-chosen non-participation in the resurrection\'s light.</p>',
    "9": '<p>A shadow: "Before your cooking pots have felt the heat of the thornwood — both green and dry — he will whirl them away." The sudden divine judgment that comes before human preparations are complete — before the pot even heats — is the Psalm\'s imagery of the unexpectedness of divine action against the violent. Luke 12:20: "You fool! This very night your life will be demanded from you." The divine whirlwind that sweeps away the wicked before they complete their plans is the eschatological judgment that Christ both announces and will execute at his return (Matt 24:27: "For as lightning comes from the east and is visible even in the west, so will be the coming of the Son of Man").</p>',
    "10": '<p>A revelation of God: "The righteous will rejoice when they see justice carried out; they will wash their feet in the blood of the wicked." The eschatological rejoicing of the righteous at divine justice — a visceral image of vindication — must be understood within ANE warfare imagery. Revelation 19:2: "for true and just are his judgments. He has condemned the great prostitute who corrupted the earth by her adulteries. He has avenged on her the blood of his servants." The righteous rejoicing at divine justice in Psalm 58:10 is the heavenly worship of Revelation 19 — the declaration that YHWH\'s judgments are "true and just" as the vindication of the martyred righteous.</p>',
    "11": '<p>A revelation of God: "Then people will say, \'There really is a reward for the righteous; truly there is a God who judges the earth.\'" The eschatological confession — that divine governance of the earth is real, that righteousness is rewarded — is the conclusion the Psalm drives toward. Acts 17:31: "For he has set a day when he will judge the world with justice by the man he has appointed. He has given proof of this to everyone by raising him from the dead." The "God who judges the earth" of Psalm 58:11 acts through the one raised from the dead — Christ as the appointed judge whose resurrection proves the eschatological governance of YHWH is real.</p>',
  },
  "59": {
    "1": '<p>A theme: Psalm 59 is a Michtam of David when Saul sent men to watch the house and kill him (1 Sam 19:11-17). The historical specificity of the superscription makes this a "David as fugitive" psalm. "Rescue me from my enemies, O my God; set me beyond the reach of those who rise up against me." The prayer for rescue from organized, state-sponsored assassination is the prayer that Christ\'s community prays under persecution. Hebrews 13:6: "So we say with confidence, \'The Lord is my helper; I will not be afraid. What can mere mortals do to me?\'" Christ himself was the object of organized state violence (Pilate + Herod + Sanhedrin) — and was rescued through the resurrection.</p>',
    "2": '<p>A theme: "Rescue me from those who do evil, and save me from men who want my blood." The bloodthirst of the evildoers — men who specifically "want my blood (<em>ʾanšê dāmîm</em>)" — is the Passion\'s language. Matthew 27:25: "His blood is on us and on our children!" — the very blood that the crowd invokes is the blood of the new covenant (Matt 26:28: "This is my blood of the covenant, which is poured out for many for the forgiveness of sins"). The men who wanted Christ\'s blood, in demanding it, unwittingly invoked its redemptive power upon themselves.</p>',
    "3": '<p>A type: "For see — they lie in ambush for my life; fierce men are gathering against me — not for any offense or sin of mine, LORD." The declaration of innocence — no offense or sin on the Psalmist\'s part justifying the attack — is fulfilled literally in Christ. John 19:4: "Pilate announced again, \'Look, I am bringing him out to you to let you know that I find no basis for a charge against him.\'" Luke 23:47: "the centurion... said, \'Surely this was a righteous man.\'" The innocence-before-attackers of Psalm 59:3 is not merely David\'s aspirational claim but Christ\'s literal truth: no offense, no sin, yet surrounded.</p>',
    "4": '<p>A type: "For no fault of mine they have mobilized against me. Arouse yourself, come to meet me, and look!" The prayer "arouse yourself, come to meet me" is the prayer for divine waking — YHWH rousing himself from apparent inactivity in the face of innocent suffering. This prayer appears to be unanswered at the cross — God seems asleep. But Acts 2:24: "God raised him from the dead, freeing him from the agony of death, because it was impossible for death to keep its hold on him." The divine self-rousing that the Psalm prays for is the resurrection — YHWH "coming to meet" the innocent one entombed by his enemies.</p>',
    "5": '<p>A revelation of God: "You are the LORD God of hosts, the God of Israel — rouse yourself to punish all the nations; show no mercy to those who commit treason with evil intent." The invocation of YHWH Ṣĕbāʾôt ("LORD of hosts/armies") is the divine warrior title that grounds the prayer for just punishment of treacherous nations. The NT situates this judgment in Christ: Revelation 19:11-16 presents Christ as the divine warrior on the white horse, "KING OF KINGS AND LORD OF LORDS" — the YHWH of hosts who now rides in final judgment through his anointed Son. The nations who committed treason against the Messiah face the LORD of hosts through Christ.</p>',
    "6": '<p>A shadow: "They return each evening, howling like dogs and circling around the city." The nocturnal surveillance — prowling, howling, circling — is the imagery of predatory persistent threat. John 18:3: "So Judas came to the garden, guiding a detachment of soldiers and some officials from the chief priests and the Pharisees. They were carrying torches, lanterns and weapons." The evening arrival at Gethsemane with torches and weapons is the fulfillment of the nocturnal predators of Psalm 59:6 — they come at night, circling the place of prayer.</p>',
    "7": '<p>A shadow: "Listen — they pour out venom with their mouths; their lips are full of swords, for they think, \'Who is going to hear?\'" The self-confident secrecy of those who conspire with weapon-words — "who is going to hear?" — is the arrogance of those who believe their plans are hidden from YHWH. Matthew 26:3-4 records the Sanhedrin plotting in the high priest\'s palace — in secret, they believe. But Acts 2:23 reveals the divine surveillance: God\'s "deliberate plan and foreknowledge" covered even this secret conspiracy. The "who is going to hear?" of Psalm 59:7 is answered: YHWH heard and incorporated it into the redemptive plan.</p>',
    "8": '<p>A revelation of God: "But you, LORD, laugh at them; you scoff at all the nations." The divine laughter at those who conspire against the anointed is the exact phrase of Psalm 2:4 ("He who sits in the heavens laughs; the Lord scoffs at them"). Psalm 2 is explicitly Messianic (2:2 "against the LORD and against his Anointed"). The divine laugh in Psalm 59:8 at those who surrounded David with weapons is the same divine scoff at those who surrounded Christ with torches and arrested him — in the absolute confidence that YHWH\'s plan would not be derailed by human weapons and conspiracies.</p>',
    "9": '<p>A revelation of God: "O my Strength, I will wait on you; for God is my fortress." The divine title "my Strength" (<em>ʿuzzî</em>) and "my fortress" (<em>miśgabbî</em>) establishes YHWH as the source of both active power and defensive security. 2 Corinthians 12:9-10: "My power is made perfect in weakness... For when I am weak, then I am strong." The paradox that Paul articulates — weakness as the context for divine strength — is the shape of Christ\'s entire ministry: the vulnerable incarnate one waiting on the Father, whose power is made perfect through and despite weakness.</p>',
    "10": '<p>A revelation of God: "The God of my steadfast love will come ahead of me; God will let me look in triumph on my enemies." The divine precedence — YHWH going ahead of the Psalmist — and the promised triumph-view over enemies is the covenant military pattern. The resurrection is the divine going-ahead: Christ rises before the disciples see him; the angels precede the disciples to the tomb (Matt 28:6: "He has risen, just as he said"). Romans 8:37: "in all these things we are more than conquerors through him who loved us." The God who "comes ahead" to grant triumph is the Father who raised Christ first, enabling the community\'s triumph through him.</p>',
    "11": '<p>A shadow: "Do not kill them, so my people will not forget; bring them down by your power and humble them, O Lord our shield!" The prayer to humiliate rather than annihilate — so the lesson is not lost — is the Psalm\'s pedagogical approach to justice. The NT\'s vision of eschatological judgment includes a memorial function: Revelation 20:12, "the dead were judged according to what they had done as recorded in the books." The divine remembering and recording that makes judgment pedagogically meaningful is the same divine attentiveness that ensures the enemies of the Messiah do not simply disappear — their accountability stands.</p>',
    "12": '<p>A shadow: "For the sin of their mouths and the words of their lips, let them be ensnared in their own pride. For the cursing and deception that they utter." The judgment corresponding to weapon-speech — "ensnared in their own pride" — is the justice principle of Proverbs 18:7: "The mouths of fools are their undoing." At the trial of Jesus, the false witnesses contradict each other (Mark 14:56-59), the high priest tears his robes in a forbidden act (Lev 21:10, making him ritually impure), and Pilate\'s verdict is written in three languages as a permanent testimony (John 19:20). The conspirators are repeatedly ensnared by their own words and actions.</p>',
    "13": '<p>A revelation of God: "Consume them in your wrath; consume them until they are no more, so that people may know that God rules over Jacob to the ends of the earth." The eschatological consumption of the enemies is not vindictiveness but revelation: the goal is that all the earth know that God rules. Acts 17:31 frames the judgment through Christ as the demonstration of divine governance: "He has given proof of this to everyone by raising him from the dead." The resurrection is the "so that people may know that God rules" of Psalm 59:13 — the proof of YHWH\'s sovereignty enacted through the Messiah.</p>',
    "14": '<p>A shadow: "They return each evening, howling like dogs and circling the city." The refrain of v6 repeated is the Psalm\'s structural reminder that the threat is persistent — it returns each evening, not a one-time crisis. The sustained, returning opposition to Christ across his ministry (John 7:1, 7:32, 8:59, 10:31, 11:53) is this same pattern: each new encounter brings renewed attempts to arrest or kill him. The howling-dogs-circling-city is the accumulated hostility that the Gospels chronicle over three years of ministry.</p>',
    "15": '<p>A theme: "They roam around in search of food; they growl when they are not satisfied." The predatory unsatisfied hunger of the enemies — prowling, growling without satiation — is the portrait of those whose hunger for power and control cannot be fulfilled. Luke 23:23: "But with loud shouts they insistently demanded that he be crucified, and their shouts prevailed." The crowd\'s insatiable demand — demanding more (crucifixion after flogging, thorns, and mockery were not enough) — is the unsatisfied hunger of Psalm 59:15, whose appetite grows with feeding.</p>',
    "16": '<p>A revelation of God: "But I will sing of your strength; I will sing aloud of your steadfast love in the morning; for you have been my fortress and my place of refuge in my day of distress." The morning singing of divine strength and steadfast love — the dawn of praise after the night of howling enemies — is the resurrection-morning image. Mark 16:2: "Very early on the first day of the week, just after sunrise, they were on their way to the tomb." The morning of the resurrection is the "morning" of Psalm 59:16 — the dawn after the dark night of the Passion in which the community sings of strength and steadfast love.</p>',
    "17": '<p>A revelation of God: "O my Strength, I will sing praise to you; for God is my fortress, the God who shows me steadfast love." The closing declaration — God as Strength, Fortress, and Steadfast Love — completes the Psalm with a triple assertion of divine character against which no enemy prevails. These three divine attributes are embodied in Christ: 1 Corinthians 1:24 ("Christ the power of God and the wisdom of God"), Ephesians 2:14 ("he himself is our peace"), and Romans 8:39 ("nothing will be able to separate us from the love of God that is in Christ Jesus our Lord"). The Psalm\'s closing divine portrait is the character of the Father as expressed in the Son.</p>',
  },
  "60": {
    "1": '<p>A revelation of God: Psalm 60 is a communal lament after military defeat — historically connected to the Aramean campaigns of 2 Samuel 8 and 10. "O God, you have rejected us and broken our defenses; you have been angry — restore us!" The experience of divine rejection in military defeat is the covenant community\'s crisis. The NT community\'s lament is structured similarly: Romans 8:36 (quoting Ps 44:22: "For your sake we face death all day long") — the apparent rejection by God is reframed in the resurrection. The restoration prayer ("restore us") is answered in Christ who takes the covenant people through apparent rejection to vindication.</p>',
    "2": '<p>A revelation of God: "You have made the earth shake; you have cracked it open; heal its fractures, for it is collapsing." The earthquake of divine judgment on the covenant community — the ground splitting under them — echoes the creation accounts where the earth is the arena of divine action. At the crucifixion, Matthew 27:51: "the earth shook, the rocks split." The earthquake of Psalm 60:2 is a type of the cosmic disturbance of the cross — the moment when YHWH\'s judgment-and-salvation falls in a way that shakes the earth literally. The prayer "heal its fractures" is answered in the new creation (Rev 21:5: "I am making everything new!").</p>',
    "3": '<p>A theme: "You have put your people through severe trials; you have made us drink disorienting wine." The wine of disorientation — the divine cup of judgment that produces incoherence — is the Passion\'s own language. Mark 14:36: "Take this cup from me." John 18:11: "Shall I not drink the cup the Father has given me?" Christ drinks the cup of divine judgment that the covenant people could not bear — 2 Corinthians 5:21: "God made him who had no sin to be sin for us." The "disorienting wine" of Psalm 60:3 is the cup that Christ drinks so his people do not have to.</p>',
    "4": '<p>A direct connection: "You have set up a banner (<em>nēs</em>) for those who fear you, for them to rally to in the face of the enemy\'s bow." The battle-banner or standard (<em>nēs</em>) raised for the fearers to rally around is a theme that runs through Isaiah: 11:12 ("He will raise a banner for the nations and gather the exiles of Israel"), 49:22 ("I will lift up my banner to the peoples"). Isaiah 11:10 uses the same term for the Messianic Root of Jesse as the banner for the nations — cited by Paul in Romans 15:12. Most directly: John 3:14, "Just as Moses lifted up the snake in the desert, so the Son of Man must be lifted up" — Christ crucified is the <em>nēs</em> raised for all who fear God to rally around.</p>',
    "5": '<p>A revelation of God: "Save your dear ones — rescue them by your right hand, and answer our prayer." The prayer for salvation "by your right hand" is the Exodus language: Exodus 15:6, "Your right hand, LORD, was majestic in power; your right hand, LORD, shattered the enemy." Acts 2:33: "Exalted to the right hand of God, he has received from the Father the promised Holy Spirit." The "right hand" that saves is the right hand where Christ now sits — the one who is both the agent of the right-hand rescue and the one who occupies that position of power on behalf of his people.</p>',
    "6": '<p>A revelation of God: "God has spoken in his holiness: \'I will triumph; I will divide up Shechem and portion out the Valley of Succoth.\'" The divine oracle of triumph — YHWH declaring victory over the territories — is the covenant-land speech pattern. The NT applies the territorial-triumph language eschatologically: Revelation 21:1-4 (the new heaven and earth), and Matthew 28:18 ("all authority in heaven and on earth has been given to me"). The "I will triumph" of the divine oracle is fulfilled in Christ who has been given all authority — the triumph over the nations that Psalm 60:6 announces is his.</p>',
    "7": '<p>A direct connection: "\'Gilead is mine, Manasseh is mine; Ephraim is my helmet; Judah is my scepter.\'" "Judah is my scepter (<em>mĕḥōqĕqî</em>)" — the lawgiver/commander\'s staff belonging to Judah — directly echoes Genesis 49:10: "The scepter will not depart from Judah, nor the ruler\'s staff from between his feet, until he to whom it belongs shall come and the obedience of the nations shall be his." Revelation 5:5: "See, the Lion of the tribe of Judah, the Root of David, has triumphed." Christ is the one to whom the scepter of Judah belongs — the fulfillment of Jacob\'s blessing and the divine oracle of Psalm 60:7.</p>',
    "8": '<p>A shadow: "\'Moab is my washbasin; over Edom I throw my sandal; over Philistia I shout in triumph.\'" The dismissive, humiliating language about the surrounding enemies — Moab as a basin, Edom receiving a thrown sandal — is the imagery of total suzerainty. The nations around Israel that opposed the Davidic kingdom are types of all powers hostile to the Messianic reign. Revelation 19:15: "He will rule them with an iron scepter. He treads the winepress of the fury of the wrath of God Almighty." The contemptuous dominion of Psalm 60:8 is the eschatological dominion of Christ over all hostile powers.</p>',
    "9": '<p>A theme: "Who will bring me into the fortified city? Who will guide me all the way to Edom?" The military question — what human commander can conquer the impregnable fortress? — is the admission of human inadequacy before the task. John 15:5: "apart from me you can do nothing." The community that cannot take the fortified city by its own power needs a guide and captain. Hebrews 2:10 calls Christ the "pioneer of their salvation" — the <em>archēgos</em> who leads the community through what they cannot accomplish themselves. The guide to Edom is the one who has already gone ahead.</p>',
    "10": '<p>A revelation of God: "Have you not rejected us, O God? You no longer go out, God, with our armies." The apparent divine absence from the covenant community\'s military struggles is the lament at the center of Psalm 60. This is the "dark night" of the Psalm — God seems to have abandoned the enterprise. Romans 8:31-32: "If God is for us, who can be against us? He who did not spare his own Son, but gave him up for us all — how will he not also, along with him, graciously give us all things?" The apparent abandonment of God going out with the armies is resolved in Christ: God\'s "going out" with the covenant community is now his going out in Christ, through the Spirit.</p>',
    "11": '<p>A revelation of God: "Give us help against the enemy, for human deliverance is worthless." The definitive confession of human inability — "human deliverance is worthless (<em>šāwʾ tĕšûʿat ʾādām</em>)" — is the OT anti-humanism that grounds the necessity of divine salvation. Acts 4:12: "Salvation is found in no one else, for there is no other name under heaven given to mankind by which we must be saved." The "worthless" human deliverance of Psalm 60:11 is the backdrop against which the name of Jesus stands out as the one non-human, non-worthless salvation available. Christ alone is the help against the enemy that no human power can supply.</p>',
    "12": '<p>A revelation of God: "Through God we will do great deeds; he himself will crush our enemies." The final declaration of divine-human cooperation — "through God" (<em>bēʾlōhîm</em>) great deeds, but YHWH himself doing the crushing — is the Christological framework of the NT. Philippians 4:13: "I can do all this through him who gives me strength." Colossians 2:15: "And having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross." The "through God we do great deeds / he himself crushes our enemies" of Psalm 60:12 is the cross: the community works through Christ; Christ crushes the enemies by his own action at Golgotha.</p>',
  },
  "61": {
    "1": '<p>A theme: Psalm 61 is a brief royal prayer for the king\'s long life, attributed to David. "Hear my cry, O God; listen to my prayer." The simplicity of the opening petition — hear, listen — is the model of prayer that Christ teaches (Matt 6:9: "Our Father in heaven"). Hebrews 5:7: "During the days of Jesus\'s life on earth, he offered up prayers and petitions with fervent cries and tears to the one who could save him from death, and he was heard because of his reverent submission." The "hear my cry" of Psalm 61:1 is the prayer posture that Christ himself occupied — and the Father heard.</p>',
    "2": '<p>A direct connection: "From the ends of the earth I call out to you when my heart grows faint; lead me to the rock that is higher than I." The "rock that is higher than I (<em>ṣûr yārûm mimmennî</em>)" — the inaccessible rock that only God can reach — is the Christological image that 1 Corinthians 10:4 makes explicit: "they drank from the spiritual rock that accompanied them, and that rock was Christ." The rock higher than the Psalmist is the one the Psalmist cannot reach by himself — and which, in Christ, descends to the level of human accessibility. The high rock comes down; the Incarnation is the rock becoming reachable.</p>',
    "3": '<p>A revelation of God: "For you have been a shelter for me, a strong tower against the enemy." The strong tower as divine protection recalls Proverbs 18:10: "The name of the LORD is a fortified tower; the righteous run to it and are safe." In the NT, the "strong tower" is the one who prays for his people: John 17:15, "My prayer is not that you take them out of the world but that you protect them from the evil one." Christ as the sheltering tower for his community — the intercessor who prays for their protection — fulfills the imagery of Psalm 61:3 in the most personal way possible.</p>',
    "4": '<p>A theme: "I will dwell in your tent forever; I will take refuge under the shelter of your wings." The desire for permanent divine dwelling — "forever" (<em>ʿôlāmîm</em>) — is the eschatological longing beneath every lament. John 14:2-3: "My Father\'s house has many rooms... I am going there to prepare a place for you. And if I go and prepare a place for you, I will come back and take you to be with me that you also may be where I am." The permanent dwelling in the divine tent of Psalm 61:4 is the "room in the Father\'s house" that Christ prepares — the eschatological shelter under divine wings that his people will inhabit forever.</p>',
    "5": '<p>A revelation of God: "For you, O God, have heard my vows; you have given me the inheritance of those who fear your name." The inheritance of the fearers of YHWH — given as the answer to heard prayer — is the covenant gift. Ephesians 1:11: "In him we were also chosen, having been predestined according to the plan of him who works out everything in conformity with the purpose of his will." And 1:14: "who is a deposit guaranteeing our inheritance." Christ is the guarantee of the inheritance — the one through whom the inheritance that God "gives to those who fear his name" is secured for all who are in him.</p>',
    "6": '<p>A direct connection: "You will extend the king\'s days; his years shall span many generations." The royal prayer for the king\'s longevity is a standard element of ancient Near Eastern royal liturgy — but it reaches its literal fulfillment only in Christ. Luke 1:33: "he will reign over Jacob\'s descendants forever; his kingdom will never end." Hebrews 7:24-25: "because Jesus lives forever, he has a permanent priesthood. Therefore he is able to save completely those who come to God through him, because he always lives to intercede for them." The "many generations" of the king\'s years in Psalm 61:6 is fulfilled in the one whose years literally span eternity.</p>',
    "7": '<p>A direct connection: "May he dwell before God forever; appoint steadfast love and faithfulness to guard him." The king\'s permanent presence before God — and the divine appointment of ḥesed and ʾĕmet (steadfast love and faithfulness) as his personal guard — is fulfilled in Christ\'s ascension and present session. Hebrews 9:24: "Christ did not enter a sanctuary made with human hands... he entered heaven itself, now to appear for us in God\'s presence." Christ "dwells before God forever" — in the heavenly sanctuary, in the presence of the Father, perpetually interceding. And John 1:14: "full of grace and truth" — steadfast love and faithfulness personified, guarding the one who is their embodiment.</p>',
    "8": '<p>A revelation of God: "So I will sing praise to your name forever, as I fulfill my vows day after day." The eternal praise — name-singing that does not stop — and the daily vow-fulfillment are the liturgical response to the divine faithfulness that Psalm 61 celebrates. Revelation 5:13: "Then I heard every creature in heaven and on earth and under the earth and on the sea, and all that is in them, saying: \'To him who sits on the throne and to the Lamb be praise and honor and glory and power, for ever and ever!\'" The "forever" of Psalm 61:8\'s praise is enacted in the eternal worship of Christ the Lamb — the praise that all creation sustains without ceasing around the throne of the one who extended the King\'s days forever.</p>',
  }
}

# INTENT: mkt-christ for Psalms 55–61 — betrayal-type cluster (Ps 55: vv12-14 Judas
#   companion type, v22 → 1 Pet 5:7 direct), trust-under-threat (Ps 56: v4 → Heb 13:6
#   direct; v13 light-of-living → resurrection), cave-psalm refuge-and-exaltation (Ps 57:
#   v1 wings → Matt 23:37; v9 → Rom 15:9 Gentile-praise citation), imprecatory justice
#   (Ps 58: v4 → Rom 3:13 direct; v11 → Acts 17:31 judgment through Christ), innocent
#   fugitive (Ps 59: v3 innocence → John 19:4; v8 laugh → Ps 2:4 pattern), military-
